    contras: ["—"],
    sides: ["Zeitinvestition"],
    studies: [{"title": "Sleep duration and all-cause mortality: a systematic review and meta-analysis (Cappuccio et al.)", "authors": "Cappuccio et al.", "year": 2010, "journal": "Sleep", "design": "Metaanalyse", "n": 1382999, "url": "https://academic.oup.com/sleep/article/33/5/585/2454478", "finding": "Kurzer Schlaf (<7 Stunden) RR 1,12 für Gesamtmortalität; langer Schlaf (>8-9h) RR 1,30.", "limitations": "Langer Schlaf kann ein Hinweis auf eine Grunderkrankung sein."}, {"title": "Sleep regularity is a stronger predictor of mortality than sleep duration (Windred et al.)", "authors": "Windred et al.", "year": 2024, "journal": "Sleep", "design": "Kohorte (UK Biobank)", "n": 60977, "url": "https://academic.oup.com/sleep/article/47/1/zsad253/7280269", "finding": "Der Schlafregelmäßigkeitsindex übertraf die Schlafdauer als Prädiktor für die Gesamt- und Krebsmortalität.", "limitations": "Beobachtungsdaten."}, {"title": "Effects of Slow Wave Sleep Deprivation on Insulin Resistance", "authors": "Tasali et al.", "year": 2008, "journal": "PNAS", "design": "RCT (Mechanismus)", "n": 9, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=Effects%20of%20Slow%20Wave%20Sleep%20Deprivation%20on%20Insulin%20Resistance", "finding": "Drei Nächte selektiver Tiefschlafunterdrückung (ohne Veränderung der Gesamtschlafzeit) reduzierten die Insulinsensitivität um 25 % – vergleichbar mit einer Gewichtszunahme von 9 kg. Mechanismusbeweise, dass Tiefschlaf besonders wichtig für die Stoffwechselgesundheit ist.", "limitations": "Winzige Stichprobe (n=9); kurzfristig; Laborumgebung."}, {"title": "Effect of one night's sleep deprivation on amyloid-β42 in human cerebrospinal fluid", "authors": "Shokri-Kojori et al.", "year": 2018, "journal": "PNAS", "design": "Crossover (Mechanismus)", "n": 20, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=Effect%20of%20one%20night%27s%20sleep%20deprivation%20on%20amyloid-%CE%B242%20in%20human%20cerebrospinal%20fluid", "finding": "Eine Nacht mit Schlafentzug erhöhte das Amyloid-β im Gehirn bei gesunden Erwachsenen um 5 % – ein direkter Evidenz dafür, dass die glymphatische Clearance-Hypothese für das Alzheimer-Risiko von Bedeutung ist.", "limitations": "Kleine Stichprobe; eine Nacht nicht chronisch; PET-Bildgebungs-Proxy."}, {"title": "Cognitive Behavioral Therapy for Insomnia in Older Adults: A meta-analysis", "authors": "Irwin et al.", "year": 2017, "journal": "Sleep", "design": "Metaanalyse von RCTs", "n": 1881, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=Cognitive%20Behavioral%20Therapy%20for%20Insomnia%20in%20Older%20Adults%3A%20A%20meta-analysis", "finding": "CBT-I führte bei älteren Erwachsenen zu mäßigen bis großen Verbesserungen der Einschlaflatenz, des Aufwachens nach dem Einschlafen und der Schlafeffizienz; Die Wirkung hielt auch nach der 6-monatigen Nachuntersuchung an. CBT-I ist laut AASM nun die erste Wahl, vor der Pharmakotherapie.", "limitations": "Heterogene CBT-I-Abgabe; ältere Erwachsene untersucht – breitere Generalisierbarkeit weniger etabliert."}],
