    studies: [{"title": "Conventional and genetic evidence on alcohol and vascular disease aetiology (Millwood et al.)", "authors": "Millwood et al.", "year": 2019, "journal": "Lancet", "design": "Mendelsche Randomisierung (China Kadoorie)", "n": 512715, "url": "https://www.thelancet.com/journals/lancet/article/PIIS0140-6736(18)31772-0/fulltext", "finding": "Die Analyse genetischer Instrumente zeigt, dass Alkohol das Schlaganfallrisiko monoton erhöht. Die „J-Kurve“ ist verwirrend, nicht die Biologie.", "limitations": "Spezifische Populationsgenetik."}, {"title": "Alcohol use and burden for 195 countries and territories, 1990-2016 (GBD 2016 Alcohol Collaborators)", "authors": "GBD 2016 Alcohol Collaborators", "year": 2018, "journal": "Lancet", "design": "Modellieren", "n": null, "url": "https://www.thelancet.com/journals/lancet/article/PIIS0140-6736(18)31310-2/fulltext", "finding": "Der Grad des Alkoholkonsums, der den Gesundheitsverlust minimierte, lag bei Null.", "limitations": "Ökologisch/Modellierung."}],
