    studies: [{"title": "How common is vitamin B-12 deficiency?", "authors": "Allen LH", "year": 2009, "journal": "Am J Clin Nutr", "design": "Rezension", "n": null, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=How%20common%20is%20vitamin%20B-12%20deficiency%3F", "finding": "Ein B12-Mangel betrifft weltweit 10–30 % der älteren Erwachsenen; Die Raten sind bei Veganern/Vegetariern und Menschen mit atrophischer Gastritis höher. Ein subklinischer Mangel ist viel häufiger als eine offene Anämie.", "limitations": "Rezensionsartikel. Die Definitionen von Mangel variieren je nach Studie."}, {"title": "Effects of homocysteine-lowering with folic acid plus vitamin B12 vs placebo on stroke and other vascular events in patients with stroke or transient ischemic attack", "authors": "VITATOPS Trial Study Group", "year": 2010, "journal": "Lancet Neurol", "design": "RCT (3,4 Jahre)", "n": 8164, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=Effects%20of%20homocysteine-lowering%20with%20folic%20acid%20plus%20vitamin%20B12%20vs%20placebo%20on%20stroke%20and%20other%20vascular%20events%20in%20patients%20with%20stroke%20or%20transient%20ischemic%20attack", "finding": "Folat + B12 + B6 senkten Homocystein, reduzierten jedoch nicht das Wiederauftreten von Schlaganfällen oder zusammengesetzten vaskulären Ereignissen im Vergleich zu Placebo über einen Zeitraum von 3,4 Jahren.", "limitations": "Negatives Ergebnis – es wurde direkt getestet, ob eine B-Vitamin-Supplementierung Ereignisse in der Bevölkerung ohne Mangel verhindert. Nicht."}],
