    studies: [{"title": "Coffee consumption and health: umbrella review of meta-analyses of multiple health outcomes", "authors": "Poole R, Kennedy OJ, Roderick P, Fallowfield JA, Hayes PC, Parkes J", "year": 2017, "journal": "BMJ", "design": "Umbrella-Review (201 Metaanalysen)", "n": null, "url": "https://pubmed.ncbi.nlm.nih.gov/29167102/", "finding": "3–4 Tassen/Tag: 17 % geringere Gesamtmortalität, 19 % geringere kardiovaskuläre Mortalität, 30 % geringere T2D-Inzidenz, 31 % geringere Parkinson-Inzidenz, weniger Leberzirrhose und HCC. J-förmige Kurve mit optimaler Größe bei 3–4 Körbchen.", "limitations": "Alles beobachtend. Voreingenommenheit gegenüber gesunden Benutzern möglich. Verschiedene Kaffeezubereitungen gebündelt."}, {"title": "Long-term coffee consumption, caffeine metabolism genetics, and risk of cardiovascular disease: a prospective analysis of up to 347,077 individuals", "authors": "Zhou A, Hyppönen E", "year": 2019, "journal": "Am J Clin Nutr", "design": "Prospektive Kohorte (UK Biobank + Mendelsche Randomisierung)", "n": 347077, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=Long-term%20coffee%20consumption%2C%20caffeine%20metabolism%20genetics%2C%20and%20risk%20of%20cardiovascular%20disease%3A%20a%20prospective%20analysis%20of%20up%20to%20347%2C077%20individuals", "finding": "Kaffeekonsum ist in U-Form umgekehrt mit dem Risiko einer Herz-Kreislauf-Erkrankung verbunden. Die Mendelsche Randomisierung unter Verwendung von CYP1A2- und AHR-Varianten stützte einen wahrscheinlichen kausalen Zusammenhang für eine moderate Einnahme (3–4 Tassen/Tag).", "limitations": "Mendelsche Randomisierungsannahmen. Kohorte nur für Großbritannien."}],
