    studies: [{"title": "GlyNAC supplementation in older adults improves glutathione deficiency, oxidative stress, mitochondrial dysfunction, inflammation, insulin resistance, endothelial dysfunction, genotoxicity, muscle strength, and cognition (Kumar et al.)", "authors": "Kumar, Sekhar et al.", "year": 2021, "journal": "Clinical and Translational Medicine", "design": "Pilot-RCT", "n": 24, "url": "https://onlinelibrary.wiley.com/doi/10.1002/ctm2.372", "finding": "Nach 16 Wochen verbesserten sich nahezu alle gemessenen Alterungsmerkmale. Effektgröße groß.", "limitations": "Kleines N; ein Labor; Replikation erwartet."}],
