    studies: [{"title": "Dietary magnesium intake and risk of cardiovascular disease, type 2 diabetes, and all-cause mortality (Fang et al. meta-analysis)", "authors": "Fang et al.", "year": 2016, "journal": "BMC Medicine", "design": "Metaanalyse", "n": 1000000, "url": "https://bmcmedicine.biomedcentral.com/articles/10.1186/s12916-016-0742-z", "finding": "Jeder Anstieg des Magnesiumgehalts in der Nahrung um 100 mg/Tag war mit einem um 22 % geringeren Herzinsuffizienzrisiko, einem um 7 % geringeren Schlaganfallrisiko, einem um 19 % geringeren Typ-2-Diabetes-Syndrom und einer um 10 % geringeren Gesamtmortalität verbunden.", "limitations": "Beobachtungsstudie; auf Lebensmittelbasis; verwirrend wahrscheinlich."}, {"title": "Effects of magnesium supplementation on blood pressure (Zhang et al. meta-analysis)", "authors": "Zhang et al.", "year": 2016, "journal": "Hypertension", "design": "Metaanalyse", "n": 2028, "url": "https://www.ahajournals.org/doi/10.1161/HYPERTENSIONAHA.116.07664", "finding": "Eine Magnesiumergänzung reduzierte in 11 Studien den SBP um 2 mmHg und den DBP um 1,8 mmHg.", "limitations": "Bescheidene Effektgröße."}],
