    studies: [{"title": "Mucolytic agents versus placebo for chronic bronchitis or chronic obstructive pulmonary disease", "authors": "Cazzola M, Calzetta L, Page C, Jardim J, Chuchalin AG, Rogliani P, Matera MG", "year": 2015, "journal": "Cochrane Database Syst Rev", "design": "Metaanalyse (≥30 RCTs)", "n": 13000, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=Mucolytic%20agents%20versus%20placebo%20for%20chronic%20bronchitis%20or%20chronic%20obstructive%20pulmonary%20disease", "finding": "Mukolytika (hauptsächlich NAC in einer Dosierung von 1200 mg/Tag) reduzierten Exazerbationen und verbesserten leicht die Lebensqualität bei chronischer Bronchitis/COPD im Vergleich zu Placebo. NNT ~8, um eine Exazerbation pro Jahr zu verhindern.", "limitations": "Heterogene Formulierungen. Nicht alle Probanden hatten eine durch Spirometrie bestätigte COPD."}, {"title": "Effect of N-acetylcysteine in COPD exacerbations (PANTHEON): a randomised, double-blind placebo-controlled trial", "authors": "Zheng JP, Wen FQ, Bai CX, Wan HY, Kang J, Chen P, Yao WZ, Ma LJ, Li X, Raiteri L, Sardina M, Gao Y, Wang BS, Zhong NS", "year": 2014, "journal": "Lancet Respir Med", "design": "RCT (1 Jahr)", "n": 1006, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=Effect%20of%20N-acetylcysteine%20in%20COPD%20exacerbations%20%28PANTHEON%29%3A%20a%20randomised%2C%20double-blind%20placebo-controlled%20trial", "finding": "NAC 600 mg zweimal täglich reduzierte die Exazerbationsrate im Vergleich zu Placebo über einen Zeitraum von einem Jahr bei mittelschwerer bis schwerer COPD um 22 %. Der größte Nutzen besteht bei Patienten mit häufigen vorangegangenen Exazerbationen.", "limitations": "Einzellandversuch (China). Zeigte keine Verbesserung des forcierten exspiratorischen Volumens."}],
