    studies: [{"title": "Melatonin and mortality in elderly (Lemoine et al.)", "authors": "Lemoine et al.", "year": 2007, "journal": "Journal of Sleep Research", "design": "RCT", "n": 354, "url": "https://onlinelibrary.wiley.com/doi/10.1111/j.1365-2869.2007.00613.x", "finding": "PR Melatonin 2 mg verbesserte die Schlafqualität und die morgendliche Wachsamkeit bei Erwachsenen > 55, kein Mortalitätsendpunkt.", "limitations": "Ersatzendpunkt."}, {"title": "Meta-analysis of melatonin for the treatment of primary insomnia (Ferracioli-Oda et al.)", "authors": "Ferracioli-Oda et al.", "year": 2013, "journal": "PLoS ONE", "design": "Metaanalyse", "n": 1683, "url": "https://journals.plos.org/plosone/article?id=10.1371/journal.pone.0063773", "finding": "Leichte Verbesserung der Schlaflatenz (-7 Min.) und der Gesamtschlafzeit (+8 Min.).", "limitations": "Kleiner Effekt."}],
